mapper.select:
SELECT b.building_id, b.name, b.code, a.name AS apartment_name, b.floor_count, b.status, b.created_at, COUNT(r.room_id) AS room_count FROM building b LEFT JOIN apartment a ON b.apartment_id = a.apartment_id AND a.deleted_at IS NULL LEFT JOIN room r ON b.building_id = r.building_id AND r.deleted_at IS NULL WHERE b.deleted_at IS NULL
AND b.apartment_id = #{apartmentId}
AND b.name LIKE CONCAT('%', #{name}, '%')
AND b.status = #{status}
GROUP BY b.building_id ORDER BY b.created_at DESC
